def count_upper(s):
    count = 0
    for i in range(0, len(s), 2):
        if s[i] in 'AEIOU':
            count += 1
    return count

def build_aggregation(facet_name, facet_options, min_doc_count=0):
    exclude = []
    if facet_name == 'type':
        field = 'embedded.@type'
        exclude = ['Item']
    elif facet_name.startswith('audit'):
        field = facet_name
    else:
        field = 'embedded.' + facet_name
    agg_name = facet_name.replace('.', '-')
    facet_type = facet_options.get('type', 'terms')
    if facet_type == 'terms':
        agg = {'terms': {'field': field, 'min_doc_count': min_doc_count, 'size': 200}}
        if exclude:
            agg['terms']['exclude'] = exclude
    elif facet_type == 'exists':
        agg = {'filters': {'filters': {'yes': {'bool': {'must': {'exists': {'field': field}}}}, 'no': {'bool': {'must_not': {'exists': {'field': field}}}}}}}
    else:
        raise ValueError('Unrecognized facet type {} for {} facet'.format(facet_type, field))
    return (agg_name, agg)

