def greatest_common_divisor(a: int, b: int) -> int:
    while b:
        a, b = (b, a % b)
    return a

def count_duplic(lists):
    element = []
    frequency = []
    if not lists:
        return element
    running_count = 1
    for i in range(len(lists) - 1):
        if lists[i] == lists[i + 1]:
            running_count += 1
        else:
            frequency.append(running_count)
            element.append(lists[i])
            running_count = 1
    frequency.append(running_count)
    element.append(lists[i + 1])
    return (element, frequency)

def swap_count(s):
    chars = s
    count_left = 0
    count_right = 0
    swap = 0
    imbalance = 0
    for i in range(len(chars)):
        if chars[i] == '[':
            count_left += 1
            if imbalance > 0:
                swap += imbalance
                imbalance -= 1
        elif chars[i] == ']':
            count_right += 1
            imbalance = count_right - count_left
    return swap

def first_non_repeating_character(str1):
    char_order = []
    ctr = {}
    for c in str1:
        if c in ctr:
            ctr[c] += 1
        else:
            ctr[c] = 1
            char_order.append(c)
    for c in char_order:
        if ctr[c] == 1:
            return c
    return None

from typing import List

def has_close_elements(numbers: List[float], threshold: float) -> bool:
    for idx, elem in enumerate(numbers):
        for idx2, elem2 in enumerate(numbers):
            if idx != idx2:
                distance = abs(elem - elem2)
                if distance < threshold:
                    return True
    return False

def to_int(s, fallback=0):
    try:
        result = int(s)
    except ValueError:
        result = fallback
    except TypeError:
        result = fallback
    return result

def swap_count(s):
    chars = s
    count_left = 0
    count_right = 0
    swap = 0
    imbalance = 0
    for i in range(len(chars)):
        if chars[i] == '[':
            count_left += 1
            if imbalance > 0:
                swap += imbalance
                imbalance -= 1
        elif chars[i] == ']':
            count_right += 1
            imbalance = count_right - count_left
    return swap

def max_element(l: list):
    m = l[0]
    for e in l:
        if e > m:
            m = e
    return m

def max_profit(price, k):
    n = len(price)
    final_profit = [[None for x in range(n)] for y in range(k + 1)]
    for i in range(k + 1):
        for j in range(n):
            if i == 0 or j == 0:
                final_profit[i][j] = 0
            else:
                max_so_far = 0
                for x in range(j):
                    curr_price = price[j] - price[x] + final_profit[i - 1][x]
                    if max_so_far < curr_price:
                        max_so_far = curr_price
                final_profit[i][j] = max(final_profit[i][j - 1], max_so_far)
    return final_profit[k][n - 1]

