def askyesno(question, default=True):
    if default:
        question += ' [Y/n] '
    else:
        question += ' [y/N] '
    while True:
        result = input(question).upper().strip()
        if result == 'Y':
            return True
        if result == 'N':
            return False
        if not result:
            return default
        print('Please type y, n or nothing at all.')

