    frequency = []
    if not lists:
        return element
    running_count = 1
    for i in range(len(lists) - 1):
        if lists[i] == lists[i + 1]:
            running_count += 1
        else:
            frequency.append(running_count)
            element.append(lists[i])
            running_count = 1
    frequency.append(running_count)
    element.append(lists[i + 1])
    return (element, frequency)

from typing import List, Optional

def longest(strings: List[str]) -> Optional[str]:
    if not strings:
        return None
    maxlen = max((len(x) for x in strings))
    for s in strings:
        if len(s) == maxlen:
            return s

import binascii
import hashlib

def task_func(input_string, verify_hash=None):
    if not isinstance(input_string, str):
        raise TypeError('Input must be a string')
    if verify_hash is not None and (not isinstance(verify_hash, str)):
        raise TypeError('verify_hash must be a string or None')
    hashed_bytes = hashlib.sha256(input_string.encode()).digest()
    hex_encoded_hash = binascii.hexlify(hashed_bytes).decode()
    if verify_hash is not None:
        return hex_encoded_hash == verify_hash
    return hex_encoded_hash

def find_last_occurrence(A, x):
    left, right = (0, len(A) - 1)
    result = -1
    while left <= right:
        mid = (left + right) // 2
        if x == A[mid]:
            result = mid
            left = mid + 1
        elif x < A[mid]:
            right = mid - 1
        else:
            left = mid + 1
    return result

def last(arr, x, n):
    low = 0
    high = n - 1
    res = -1
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] > x:
            high = mid - 1
        elif arr[mid] < x:
            low = mid + 1
        else:
            res = mid
            low = mid + 1
    return res

def modp(n: int, p: int):
    ret = 1
    for i in range(n):
        ret = 2 * ret % p
    return ret

def shell_sort(my_list):
    gap = len(my_list) // 2
    while gap > 0:
        for i in range(gap, len(my_list)):
            current_item = my_list[i]
            j = i
            while j >= gap and my_list[j - gap] > current_item:
                my_list[j] = my_list[j - gap]
                j -= gap
            my_list[j] = current_item
        gap //= 2
    return my_list

def askyesno(question, default=True):
    if default:
        question += ' [Y/n] '
    else:
        question += ' [y/N] '
    while True:
        result = input(question).upper().strip()
        if result == 'Y':
            return True
        if result == 'N':
            return False
        if not result:
            return default
        print('Please type y, n or nothing at all.')

