import re
import collections

def task_func(string, patterns=['nnn', 'aaa', 'sss', 'ddd', 'fff']):
    if not isinstance(string, str):
        raise TypeError('Input string should be of type string.')
    if not isinstance(patterns, list):
        raise TypeError('patterns should be a list of strings.')
    if not all((isinstance(s, str) for s in patterns)):
        raise TypeError('patterns should be a list of strings.')
    pattern_counts = collections.defaultdict(int)
    for pattern in patterns:
        pattern_counts[pattern] = len(re.findall(pattern, string))
    return dict(pattern_counts)

MAX = 1000

def replace_spaces(string):
    string = string.strip()
    i = len(string)
    space_count = string.count(' ')
    new_length = i + space_count * 2
    if new_length > MAX:
        return -1
    index = new_length - 1
    string = list(string)
    for f in range(i - 2, new_length - 2):
        string.append('0')
    for j in range(i - 1, 0, -1):
        if string[j] == ' ':
            string[index] = '0'
            string[index - 1] = '2'
            string[index - 2] = '%'
            index = index - 3
        else:
            string[index] = string[j]
            index -= 1
    return ''.join(string)

from typing import List

def has_close_elements(numbers: List[float], threshold: float) -> bool:
    for idx, elem in enumerate(numbers):
        for idx2, elem2 in enumerate(numbers):
            if idx != idx2:
                distance = abs(elem - elem2)
                if distance < threshold:
                    return True
    return False

def binary_search(item_list, item):
    first = 0
    last = len(item_list) - 1
    found = False
    while first <= last and (not found):
        mid = (first + last) // 2
        if item_list[mid] == item:
            found = True
        elif item < item_list[mid]:
            last = mid - 1
        else:
            first = mid + 1
    return found

