def max_profit(price, k):
    n = len(price)
    final_profit = [[None for x in range(n)] for y in range(k + 1)]
    for i in range(k + 1):
        for j in range(n):
            if i == 0 or j == 0:
                final_profit[i][j] = 0
            else:
                max_so_far = 0
                for x in range(j):
                    curr_price = price[j] - price[x] + final_profit[i-1][x]
                    if max_so_far < curr_price:
                        max_so_far = curr_price
                final_profit[i][j] = max(final_profit[i][j-1], max_so_far)
    return final_profit[k][n-1]

def add_query_filter(cur_query, filter_type, op, value, property_name=None):
    if cur_query is None or cur_query == "":
        cur_query = "?"
    else:
        cur_query += "&"
    cur_query += "filter[" + filter_type + "]"
    if property_name is not None:
        cur_query += "[" + property_name + "]"
    return cur_query + op + str(value)

